/* Segmented control tabs */

.tc-tab-buttons {
	display: inline-flex;
	gap: 2px;
	padding: 2px;
	background-color: <<colour tab-background>>;
	background-image: linear-gradient(rgba(128,128,128,0.12), rgba(128,128,128,0.12));
	border-radius: 8px;
	border: none;
	font-size: 0.95em;
}

.tc-tab-buttons button {
	background: transparent;
	border: 1px solid transparent;
	border-radius: 6px;
	padding: 0.382em 0.618em;
	color: <<colour tab-foreground>>;
	border-bottom-left-radius: 7px;
	border-bottom-right-radius: 7px;
	margin-right: 0;
}

.tc-tab-buttons button.tc-tab-selected {
	background: <<colour background>>;
	color: <<colour foreground>>;
	font-weight: 600;
	border: 1px solid <<colour tab-border>>;
	box-shadow: inset 0 0 0 1px rgba(128,128,128,0.2);
}

.tc-tab-buttons button:hover:not(.tc-tab-selected) {
	background: transparent;
	color: <<colour foreground>>;
}

.tc-tab-divider {
	border-top: none;
}

/* Sidebar overrides — vanilla's .tc-sidebar-lists rules have higher specificity */

.tc-sidebar-lists .tc-tab-buttons {
	margin-top: .6em;
}

.tc-sidebar-lists .tc-tab-buttons button {
	background: transparent;
	background-color: transparent;
	border: 1px solid transparent;
	color: <<colour tab-foreground>>;
}

.tc-sidebar-lists .tc-tab-buttons button.tc-tab-selected {
	background: <<colour background>>;
	background-color: <<colour background>>;
	color: <<colour foreground>>;
	border: 1px solid <<colour tab-border>>;
}

.tc-sidebar-lists .tc-tab-buttons button:hover:not(.tc-tab-selected) {
	background: transparent;
	background-color: transparent;
	color: <<colour foreground>>;
}

/* link-to-tabs offset fix */
.wltc-link-to-tab {
	top: -.6em;
	left: -1.1em;
	font-size: 0.6em;
}"},"$:/themes/wikilabs/roundedtabs/license":{"title":"$:/themes/wikilabs/roundedtabs/license","license-text":"https://opensource.org/license/BSD-3-clause/","text":"[[Rounded Tabs|https://wikilabs.github.io/#roundedtabs]] (c) Mario Pietsch - 2026-<<now YYYY>>

